from __future__ import annotations
from typing import ClassVar


class RegistryMeta(type):
    """Metaclass that maintains a registry of all concrete subclasses."""

    _registry: dict[str, type] = {}

    def __new__(mcs, name: str, bases: tuple[type, ...], namespace: dict, **kwargs):
        cls = super().__new__(mcs, name, bases, namespace, **kwargs)
        # Skip registration of the base class itself
        if bases:
            key = kwargs.get("alias", name)
            if key in mcs._registry:
                raise TypeError(f"Duplicate registration: '{key}' already registered")
            mcs._registry[key] = cls
        return cls

    @classmethod
    def get(mcs, name: str) -> type:
        try:
            return mcs._registry[name]
        except KeyError:
            raise KeyError(f"No class registered as '{name}'. Available: {list(mcs._registry)}")

    @classmethod
    def all(mcs) -> dict[str, type]:
        return dict(mcs._registry)


class Handler(metaclass=RegistryMeta):
    """Base class — not registered itself."""

    def handle(self, payload: dict) -> str:
        raise NotImplementedError


class EmailHandler(Handler):
    def handle(self, payload: dict) -> str:
        return f"Email → {payload['to']}"


class SMSHandler(Handler, alias="sms"):  # custom alias
    def handle(self, payload: dict) -> str:
        return f"SMS → {payload['phone']}"


# Usage
if __name__ == "__main__":
    # Lookup by class name
    klass = RegistryMeta.get("EmailHandler")
    print(klass().handle({"to": "a@b.com"}))  # Email → a@b.com

    # Lookup by alias
    klass = RegistryMeta.get("sms")
    print(klass().handle({"phone": "+1234"}))  # SMS → +1234

    print(RegistryMeta.all().keys())  # dict_keys(['EmailHandler', 'sms'])
```

Key points:
- `_registry` lives on the metaclass, shared across all classes using it
- `bases` check prevents the abstract base itself from being registered
- `**kwargs` forwarding lets subclasses pass `alias=` at class definition time
- `__new__` on a metaclass receives the *class being created*, not an instance

