from __future__ import annotations
from typing import Callable, get_type_hints
import inspect


class Command:
    """
    Base class that uses __init_subclass__ to:
    1. Require subclasses to declare a `name: str` class variable
    2. Require an `execute(self) -> str` method
    3. Auto-register subclasses in a command table
    """

    _commands: dict[str, type[Command]] = {}

    def __init_subclass__(cls, /, abstract: bool = False, **kwargs: object) -> None:
        super().__init_subclass__(**kwargs)

        if abstract:
            return  # let intermediate abstract classes skip checks

        # 1. Enforce `name` class variable
        if not hasattr(cls, "name") or not isinstance(cls.name, str):
            raise TypeError(f"{cls.__qualname__} must define a `name: str` class variable")

        # 2. Enforce `execute` method with correct signature
        if "execute" not in cls.__dict__ and not any(
            "execute" in base.__dict__ for base in cls.__mro__[1:-1]
        ):
            raise TypeError(f"{cls.__qualname__} must implement execute()")

        sig = inspect.signature(cls.execute)
        params = list(sig.parameters)
        if params != ["self"]:
            raise TypeError(f"{cls.__qualname__}.execute() must take only self")

        # 3. Auto-register
        if cls.name in Command._commands:
            raise ValueError(f"Command name '{cls.name}' already taken")
        Command._commands[cls.name] = cls

    @classmethod
    def run(cls, name: str) -> str:
        klass = cls._commands.get(name)
        if klass is None:
            raise KeyError(f"Unknown command: {name!r}")
        return klass().execute()


# Abstract intermediate — skips validation
class BaseIO(Command, abstract=True):
    pass


class Ping(Command):
    name = "ping"

    def execute(self) -> str:
        return "pong"


class Echo(BaseIO):
    name = "echo"

    def execute(self) -> str:
        return "echo!"


# This would raise at class-definition time:
# class Broken(Command):
#     pass  # TypeError: Broken must define a `name: str` class variable

print(Command.run("ping"))   # pong
print(Command.run("echo"))   # echo!
print(Command._commands.keys())  # dict_keys(['ping', 'echo'])
```

`__init_subclass__` runs at class-body parse time (before any instances exist), making it ideal for enforcing contracts and building registries — all without the complexity of a metaclass.

