from abc import ABC, abstractmethod
from typing import Iterator


# ── Abstract base ──────────────────────────────────────────────────────────────
class DataSource(ABC):
    """Contract: anything that can yield typed records."""

    @property
    @abstractmethod
    def name(self) -> str:
        """Human-readable identifier for this source."""

    @abstractmethod
    def connect(self) -> None:
        """Open the connection / file handle / socket."""

    @abstractmethod
    def records(self) -> Iterator[dict]:
        """Yield records one at a time."""

    @classmethod
    @abstractmethod
    def from_config(cls, cfg: dict) -> "DataSource":
        """Factory: build an instance from a config dict."""

    def __repr__(self) -> str:
        return f"<{type(self).__name__} name={self.name!r}>"


# ── Concrete mixin (not abstract) ─────────────────────────────────────────────
class BatchMixin:
    """Adds batched iteration on top of any DataSource.records()."""

    def batches(self, size: int = 100) -> Iterator[list[dict]]:
        batch: list[dict] = []
        for record in self.records():  # type: ignore[attr-defined]
            batch.append(record)
            if len(batch) == size:
                yield batch
                batch = []
        if batch:
            yield batch


# ── Concrete implementation ───────────────────────────────────────────────────
class InMemorySource(BatchMixin, DataSource):
    def __init__(self, name: str, data: list[dict]) -> None:
        self._name = name
        self._data = data

    @property
    def name(self) -> str:
        return self._name

    def connect(self) -> None:
        pass  # nothing to open

    def records(self) -> Iterator[dict]:
        yield from self._data

    @classmethod
    def from_config(cls, cfg: dict) -> "InMemorySource":
        return cls(cfg["name"], cfg.get("data", []))


