from __future__ import annotations
from typing import Any
import functools


class ValidatingMeta(type):
    """
    Collects every method named validate_* and runs them
    in definition order inside a patched __init__.
    """

    def __new__(mcs, name: str, bases: tuple[type, ...], ns: dict[str, Any]):
        validators = [
            v for k, v in ns.items()
            if k.startswith("validate_") and callable(v)
        ]

        original_init = ns.get("__init__")

        @functools.wraps(original_init or (lambda self, *a, **kw: None))
        def __init__(self, *args: Any, **kwargs: Any) -> None:
            if original_init:
                original_init(self, *args, **kwargs)
            for validator in validators:
                validator(self)

        ns["__init__"] = __init__
        ns["_validators"] = [v.__name__ for v in validators]
        return super().__new__(mcs, name, bases, ns)


class Order(metaclass=ValidatingMeta):
    def __init__(self, item: str, qty: int, price: float) -> None:
        self.item = item
        self.qty = qty
        self.price = price

    def validate_qty(self) -> None:
        if self.qty <= 0:
            raise ValueError(f"qty must be positive, got {self.qty}")

    def validate_price(self) -> None:
        if self.price < 0:
            raise ValueError(f"price cannot be negative, got {self.price}")

    def validate_item(self) -> None:
