from __future__ import annotations
from typing import Any


class OrderTracker(dict):
    """Dict subclass that records insertion order of callables."""

    def __init__(self) -> None:
        super().__init__()
        self._method_order: list[str] = []

    def __setitem__(self, key: str, value: Any) -> None:
        if callable(value) and not key.startswith("__"):
            self._method_order.append(key)
        super().__setitem__(key, value)


class OrderedMeta(type):
    @classmethod
    def __prepare__(mcs, name: str, bases: tuple[type, ...], **kwargs) -> OrderTracker:
        # Python calls this before executing the class body
        # The returned mapping becomes the class namespace
        return OrderTracker()

    def __new__(mcs, name: str, bases: tuple[type, ...], ns: OrderTracker, **kwargs):
        cls = super().__new__(mcs, name, bases, dict(ns))
        cls._method_order = ns._method_order  # freeze for inspection
        return cls


class Pipeline(metaclass=OrderedMeta):
    def ingest(self, data): ...
    def clean(self, data): ...
    def transform(self, data): ...
    def load(self, data): ...


print(Pipeline._method_order)
# ['ingest', 'clean', 'transform', 'load']

# Practical use: run pipeline stages in definition order
class ETL(metaclass=OrderedMeta):
    def __init__(self, data):
        self.data = data

    def step_extract(self):
        print("extract")
        return self

    def step_transform(self):
        print("transform")
        return self

    def step_load(self):
        print("load")
        return self

    def run(self):
        for name in self._method_order:
            if name.startswith("step_"):
                getattr(self, name)()


ETL(None).run()
# extract
# transform
# load
```

`__prepare__` is called before the class body executes, giving you control over the namespace object Python uses to collect names. This is how `enum.EnumMeta` tracks member definition order.

