from __future__ import annotations
from typing import Callable, TypeVar, ParamSpec, Concatenate
from functools import wraps
import time
import logging

P = ParamSpec('P')   # captures the wrapped function's original parameter spec
R = TypeVar('R')     # return type

logger = logging.getLogger(__name__)


def retry(
    max_attempts: int = 3,
    delay: float = 0.5,
    exceptions: tuple[type[Exception], ...] = (Exception,),
) -> Callable[[Callable[P, R]], Callable[P, R]]:
    def decorator(func: Callable[P, R]) -> Callable[P, R]:
        @wraps(func)
        def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
            last_exc: Exception | None = None
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except exceptions as exc:
                    last_exc = exc
                    logger.warning('Attempt %d/%d failed: %s', attempt+1, max_attempts, exc)
                    if attempt < max_attempts - 1:
                        time.sleep(delay * (2 ** attempt))
            raise RuntimeError(f'All {max_attempts} attempts failed') from last_exc
        return wrapper
    return decorator


@retry(max_attempts=3, delay=0.001, exceptions=(ValueError,))
def parse_int(text: str, *, base: int = 10) -> int:
    return int(text, base)


# mypy knows: parse_int(text: str, *, base: int = 10) -> int
print(parse_int('ff', base=16))  # 255
print(parse_int('42'))           # 42


# Concatenate: inject/consume one specific leading argument
def logged(func: Callable[Concatenate[str, P], R]) -> Callable[P, R]:
    @wraps(func)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        return func('[LOG]', *args, **kwargs)
    return wrapper


@logged
def send(prefix: str, message: str, *, priority: int = 0) -> str:
    return f'{prefix} priority={priority}: {message}'


# Caller only sees (message: str, *, priority: int = 0) -> str
print(send('hello', priority=1))  # [LOG] priority=1: hello
```

`P.args` and `P.kwargs` must always be used together as a pair in `wrapper(*args: P.args, **kwargs: P.kwargs)`. Without `ParamSpec`, the wrapper has type `(*Any, **Any) -> Any` and mypy cannot validate call sites.

