from __future__ import annotations
try:
    from typing import dataclass_transform
except ImportError:
    from typing_extensions import dataclass_transform

import dataclasses
from typing import Any, Callable, TypeVar

T = TypeVar('T')


@dataclass_transform(
    eq_default=True,
    order_default=False,
    kw_only_default=False,
    field_specifiers=(dataclasses.field,),
)
def model(
    cls: type[T] | None = None,
    *,
    frozen: bool = False,
    validate: bool = True,
) -> type[T] | Callable[[type[T]], type[T]]:
    def decorator(klass: type[T]) -> type[T]:
        klass = dataclasses.dataclass(klass, frozen=frozen)  # type: ignore
        if validate:
            original_init = klass.__init__
            def validated_init(self: Any, *args: Any, **kwargs: Any) -> None:
                original_init(self, *args, **kwargs)
                for name in dir(type(self)):
                    if name.startswith('validate_'):
                        getattr(self, name)()
            klass.__init__ = validated_init  # type: ignore
        return klass
    if cls is None:
        return decorator
    return decorator(cls)


@model(frozen=True, validate=True)
class User:
    name: str
    age: int
    email: str

    def validate_age(self) -> None:
        if self.age < 0:
            raise ValueError(f'age must be >= 0, got {self.age}')

    def validate_email(self) -> None:
        if '@' not in self.email:
            raise ValueError(f'invalid email: {self.email}')


u = User(name='Alice', age=30, email='alice@example.com')
print(u)  # User(name='Alice', age=30, email='alice@example.com')

try:
    User(name='Bob', age=-1, email='bob@example.com')
except ValueError as e:
    print(e)  # age must be >= 0, got -1

try:
    u.age = 31  # type: ignore
except dataclasses.FrozenInstanceError as e:
    print(e)
```

`@dataclass_transform` is a typing-only decorator with zero runtime effect — it only communicates to mypy/pyright. This is how Pydantic, attrs, and SQLAlchemy declare their metaclass magic to type checkers. The key fields: `field_specifiers` tells checkers which functions can be used like `dataclasses.field()`.

