from __future__ import annotations
from typing import Union, Callable


# Recursive type alias: requires forward reference (string) for 3.10/3.11
JSON = Union[str, int, float, bool, None, list['JSON'], dict[str, 'JSON']]

# Python 3.12+ equivalent:
# type JSON = str | int | float | bool | None | list[JSON] | dict[str, JSON]


def json_depth(data: JSON) -> int:
    if isinstance(data, list):
        return 1 + max((json_depth(v) for v in data), default=0)
    if isinstance(data, dict):
        return 1 + max((json_depth(v) for v in data.values()), default=0)
    return 0


def json_flatten(data: JSON, prefix: str = '') -> dict[str, JSON]:
    result: dict[str, JSON] = {}
    if isinstance(data, dict):
        for k, v in data.items():
            child = f'{prefix}.{k}' if prefix else k
            result.update(json_flatten(v, child))
    elif isinstance(data, list):
        for i, v in enumerate(data):
            result.update(json_flatten(v, f'{prefix}[{i}]'))
    else:
        result[prefix] = data
    return result


def json_transform(data: JSON, fn: Callable[[JSON], JSON]) -> JSON:
    if isinstance(data, dict):
        return {k: json_transform(v, fn) for k, v in data.items()}
    if isinstance(data, list):
        return [json_transform(v, fn) for v in data]
    return fn(data)


doc: JSON = {
    'user': {'name': 'Alice', 'age': 30},
    'tags': ['admin', 'user'],
    'meta': {'created': None, 'counts': {'views': 100}},
}

print(json_depth(doc))    # 3
print(json_flatten(doc))
# {'user.name': 'Alice', 'user.age': 30, 'tags[0]': 'admin', ...}

upper = json_transform(doc, lambda v: v.upper() if isinstance(v, str) else v)
print(upper['user'])  # {'name': 'ALICE', 'age': 30}
```

Recursive type aliases require forward references (`'JSON'` in quotes) for Python 3.10/3.11 because the type isn't fully defined when first referenced. Python 3.12's `type` statement makes this explicit and avoids string quoting. The alias is purely for type checkers — at runtime, `JSON` is just the `Union` object.

