from __future__ import annotations
from abc import ABC, abstractmethod
from copy import deepcopy
from dataclasses import dataclass, field
from contextlib import contextmanager
from typing import Iterator


@dataclass
class User:
    id: int
    name: str
    email: str

    def rename(self, new_name: str) -> None:
        self.name = new_name


class UserRepository(ABC):
    @abstractmethod
    def get(self, user_id: int) -> User | None: ...
    @abstractmethod
    def add(self, user: User) -> None: ...
    @abstractmethod
    def list_all(self) -> list[User]: ...


class InMemoryUserRepository(UserRepository):
    def __init__(self, store: dict[int, User]) -> None:
        self._store = store
    def get(self, user_id: int) -> User | None:
        u = self._store.get(user_id)
        return deepcopy(u) if u else None
    def add(self, user: User) -> None:
        self._store[user.id] = deepcopy(user)
    def list_all(self) -> list[User]:
        return [deepcopy(u) for u in self._store.values()]


class UnitOfWork:
    def __init__(self, shared_store: dict[int, User]) -> None:
        self._shared = shared_store
        self._snapshot = deepcopy(shared_store)  # working copy
        self.users = InMemoryUserRepository(self._snapshot)
        self._committed = False

    def commit(self) -> None:
        self._shared.clear()
        self._shared.update(deepcopy(self._snapshot))
        self._committed = True

    def rollback(self) -> None:
        self._snapshot.clear()
        self._snapshot.update(deepcopy(self._shared))

    def __enter__(self) -> 'UnitOfWork':
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> bool:
        if exc_type is None and not self._committed:
            self.commit()
        elif exc_type is not None:
            self.rollback()
        return False


class UserService:
    def __init__(self, store: dict[int, User]) -> None:
        self._store = store

    @contextmanager
    def _uow(self) -> Iterator[UnitOfWork]:
        with UnitOfWork(self._store) as uow:
            yield uow

    def create_user(self, user_id: int, name: str, email: str) -> User:
        with self._uow() as uow:
            if uow.users.get(user_id):
                raise ValueError(f'User {user_id} exists')
            user = User(id=user_id, name=name, email=email)
            uow.users.add(user)
        return user

    def rename_user(self, user_id: int, new_name: str) -> None:
        with self._uow() as uow:
            user = uow.users.get(user_id)
            if user is None:
                raise KeyError(user_id)
            user.rename(new_name)
            uow.users.add(user)


store: dict[int, User] = {}
svc = UserService(store)
svc.create_user(1, 'Alice', 'alice@example.com')
svc.rename_user(1, 'Alicia')

with UnitOfWork(store) as uow:
    print(uow.users.get(1))  # User(id=1, name='Alicia', ...)
```

The Unit of Work works on a snapshot of the store. `commit()` atomically flushes to the shared store; `rollback()` silently discards all changes. The `__exit__` auto-commit on no-exception makes the common path ergonomic. In tests, start each test with a fresh `{}` store — no database cleanup needed.

